class Solution:
    def getMaximumGold(self, grid):
        m, n = len(grid), len(grid[0])
        best = 0
        def walk(i, j, visited, total):
            nonlocal best
            total += grid[i][j]
            if total > best:
                best = total
            for di, dj in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                ni, nj = i + di, j + dj
                if 0 <= ni < m and 0 <= nj < n and grid[ni][nj] != 0 and (ni, nj) not in visited:
                    visited.add((ni, nj))
                    walk(ni, nj, visited, total)
                    visited.discard((ni, nj))
        for i in range(m):
            for j in range(n):
                if grid[i][j] != 0:
                    walk(i, j, {(i, j)}, 0)
        return best

