class Solution:
    def getMaximumGold(self, grid):
        m, n = len(grid), len(grid[0])
        def dfs(i, j):
            if i < 0 or i >= m or j < 0 or j >= n or grid[i][j] == 0:
                return 0
            g = grid[i][j]
            grid[i][j] = 0
            best = 0
            for di, dj in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                best = max(best, dfs(i + di, j + dj))
            grid[i][j] = g
            return g + best
        ans = 0
        for i in range(m):
            for j in range(n):
                if grid[i][j] != 0:
                    ans = max(ans, dfs(i, j))
        return ans

